#include <stdlib.h>
#include <string.h>

char *reverseString(char *s) {
  int i = 0;
  int j = strlen(s) - 1;
  char *result = (char *)malloc(sizeof(char) * (strlen(s) + 1));
  while (i < j) {
    char temp = s[i];
    s[i] = s[j];
    s[j] = temp;
    i++;
    j--;
  }
  strcpy(result, s);
  return result;
}
